import{_ as a,c as l,o as i,a4 as r}from"./chunks/framework.DQgBWl2g.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note-others/driving-license/topics.md","filePath":"note-others/driving-license/topics.md"}'),e={name:"note-others/driving-license/topics.md"};function d(h,t,o,n,s,u){return i(),l("div",null,[...t[0]||(t[0]=[r('<h2 id="交通违法处罚" tabindex="-1">交通违法处罚 <a class="header-anchor" href="#交通违法处罚" aria-label="Permalink to &quot;交通违法处罚&quot;">​</a></h2><p>对道路交通安全违法行为的处罚种类包括：警告、罚款、暂扣或者吊销机动车驾驶证、拘留。</p><p>一般考题中没有警告情形；</p><h3 id="罚款金额" tabindex="-1">罚款金额 <a class="header-anchor" href="#罚款金额" aria-label="Permalink to &quot;罚款金额&quot;">​</a></h3><ul><li>涉及犯罪的，如伪造编造车牌：2000-5000。</li><li>比较严重，但未涉及犯罪的，如逃逸/非法/私自安装：200-2000。</li><li>逾期，欺骗型违法，如逾期审验机动车，隐瞒、欺骗手段补领驾驶证：200-500。</li><li>针对教练的罚款一般为 20-200（1、不在规定路线时间学车2、不贴学员标识），及其他20元情形（行为较轻微）。</li></ul><h3 id="饮酒、醉酒驾驶机动车" tabindex="-1">饮酒、醉酒驾驶机动车 <a class="header-anchor" href="#饮酒、醉酒驾驶机动车" aria-label="Permalink to &quot;饮酒、醉酒驾驶机动车&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类别</th><th>饮酒</th><th>醉酒</th></tr></thead><tbody><tr><td>标准</td><td>20mg - 80mg</td><td>&gt; 80mg</td></tr><tr><td>初次处罚(小车)</td><td>驾驶证扣6个月，1000-2000</td><td>吊销，刑责，5年不取驾驶证</td></tr><tr><td>二次处罚(小车)</td><td>吊销驾照，小10日拘留，1000-2000</td><td></td></tr><tr><td>营运车(更严格)</td><td>吊销驾照，15日拘留，5000，5年不取</td><td>吊销，10年不取驾照，可取后非营运</td></tr></tbody></table><ul><li>饮酒醉酒造成事故构成犯罪，吊销终身不取</li><li>二次处罚指饮酒驾驶被处罚后，再次饮酒驾驶</li></ul><hr><h2 id="自行协商情形" tabindex="-1">自行协商情形 <a class="header-anchor" href="#自行协商情形" aria-label="Permalink to &quot;自行协商情形&quot;">​</a></h2><p><strong>需全部满足以下条件才能自行解决</strong></p><ol><li>造成轻微伤及以下(含财物损失)</li><li>双方无争议</li><li>无附带其他道路违法行为(无证无标无牌，酒驾毒驾)</li><li>机动车可移动</li></ol><hr><h2 id="驾驶证相关" tabindex="-1">驾驶证相关 <a class="header-anchor" href="#驾驶证相关" aria-label="Permalink to &quot;驾驶证相关&quot;">​</a></h2><h3 id="不能取得驾照时间" tabindex="-1">不能取得驾照时间 <a class="header-anchor" href="#不能取得驾照时间" aria-label="Permalink to &quot;不能取得驾照时间&quot;">​</a></h3><ul><li>口诀: <strong>假1吊2撤3醉5逃终生</strong></li></ul><ol><li>假一: 提供假材料<strong>申领</strong>驾驶证的，一年内不得报考。</li><li>吊二: 吊销驾驶证后两年内不得报考。</li><li>撤三: 取得驾驶证后被撤销的，三年内不得报考。(<strong>代考，欺骗，贿赂获取驾驶证后被发现撤销</strong>)</li><li>醉五: 醉驾被吊销驾照的，五年内不得报考。(<strong>追逐竟驶、运输业超员超速构成犯罪5年</strong>)</li><li>事故犯罪；无证驾驶重伤：除醉酒外交通重大事故+构成犯罪;无证驾驶+重伤死亡；十年。</li><li>逃终身: 交通肇事逃逸的，终身不能报考驾驶证。（<strong>酒驾(包括醉酒和饮酒)犯罪，终身</strong>）</li></ol><h3 id="申请驾照中的违法行为" tabindex="-1">申请驾照中的违法行为 <a class="header-anchor" href="#申请驾照中的违法行为" aria-label="Permalink to &quot;申请驾照中的违法行为&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行为</th><th>情节</th><th>罚款</th><th>不得申请期限</th></tr></thead><tbody><tr><td>1</td><td>申领</td><td>提供虚假材料</td><td>500</td><td>1年</td></tr><tr><td>2</td><td>考试</td><td>贿赂、欺骗</td><td>2000</td><td>1年</td></tr><tr><td>3</td><td>取得</td><td>贿赂、欺骗</td><td>2000</td><td>3年</td></tr><tr><td>4</td><td>组织</td><td>贿赂、欺骗</td><td>3-5倍，10万</td><td>情节严重，3-7年</td></tr></tbody></table><h3 id="驾驶证申领地特殊情况" tabindex="-1">驾驶证申领地特殊情况 <a class="header-anchor" href="#驾驶证申领地特殊情况" aria-label="Permalink to &quot;驾驶证申领地特殊情况&quot;">​</a></h3><ul><li>现役军警: 部队驻地</li><li>境外人员: 居住地或居留地</li><li>增加准驾: 核发地</li><li>户籍地: 户籍地</li></ul><p><strong>新证居住地，增驾核发地</strong><strong>居住地不在户籍地申请，可以到居住地</strong></p><hr><h3 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h3><ul><li><p>初次不可申领驾照的情形: 大客(A1)、挂车(A2,包括轻型牵引挂车C6)、中客(B1)</p></li><li><p>办理驾驶证时的身体条件证明: 有体检资质的乡镇社区以上医疗机构，6个月有效</p></li></ul><h3 id="驾照申领年龄限制" tabindex="-1">驾照申领年龄限制 <a class="header-anchor" href="#驾照申领年龄限制" aria-label="Permalink to &quot;驾照申领年龄限制&quot;">​</a></h3><ul><li>除c1,c2外，其他都有60岁限制。</li><li>70岁以上需要每年体检，提交身体条件证明。</li><li>大客车，重型牵引挂车： 最低年龄22岁。</li><li>中型客车，大型货车： 最低年龄20岁。</li><li>其他18+。</li></ul><h3 id="轻型牵引挂车的增驾申请" tabindex="-1">轻型牵引挂车的增驾申请 <a class="header-anchor" href="#轻型牵引挂车的增驾申请" aria-label="Permalink to &quot;轻型牵引挂车的增驾申请&quot;">​</a></h3><ul><li>最近一个积分周期和本周期没满12分</li><li>已经取得手动挡、自动挡小车1年以上</li></ul><h3 id="驾驶证实习期" tabindex="-1">驾驶证实习期 <a class="header-anchor" href="#驾驶证实习期" aria-label="Permalink to &quot;驾驶证实习期&quot;">​</a></h3><p>首次取得小型汽车的实习期为12个月；如果先取得手动挡c2,之后增驾c1,不属于首次取得小型汽车，无实习期。</p><h3 id="学习驾驶证明后的学习顺序" tabindex="-1">学习驾驶证明后的学习顺序 <a class="header-anchor" href="#学习驾驶证明后的学习顺序" aria-label="Permalink to &quot;学习驾驶证明后的学习顺序&quot;">​</a></h3><ul><li>考完科目一取得学习驾驶证明后，10天后预约科目二，</li><li>考完科目一取得学习驾驶证明后30天预约科目三(自动挡20天)</li><li>考完科目二后7天后预约科目三</li></ul><hr><h3 id="驾驶证审验" tabindex="-1">驾驶证审验 <a class="header-anchor" href="#驾驶证审验" aria-label="Permalink to &quot;驾驶证审验&quot;">​</a></h3><ul><li><p>大车（AB型车）记分周期结束30天内审验，在一个记分周期内没有记分记录的，免予本记分周期审验。</p></li><li><p>一般车，发生交通事故造成人员死亡记分周期结束30天内审验</p></li></ul><hr><h2 id="行车安全" tabindex="-1">行车安全 <a class="header-anchor" href="#行车安全" aria-label="Permalink to &quot;行车安全&quot;">​</a></h2><h3 id="不得超车情形" tabindex="-1">不得超车情形 <a class="header-anchor" href="#不得超车情形" aria-label="Permalink to &quot;不得超车情形&quot;">​</a></h3><ul><li>前车正在左转弯、掉头、超车的；</li><li>与对面来车有会车可能的；(不能三车横向一线)</li><li>前车为执行紧急任务的警车、消防车、救护车、工程救险车的；</li><li>行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的。</li></ul><h3 id="明确限速" tabindex="-1">明确限速 <a class="header-anchor" href="#明确限速" aria-label="Permalink to &quot;明确限速&quot;">​</a></h3><ul><li><p>在道口，糟糕天气，转弯等情形不得超过每小时30公里。</p></li><li><p>在小区里行驶，速度不能超过5公里/小时。</p></li></ul><p><strong>城市道路、公路道路限速</strong></p><ul><li><strong>无线： 城3公4</strong></li><li><strong>有线： 城5公7</strong></li></ul><h3 id="高速能见度和车速之间的关系" tabindex="-1">高速能见度和车速之间的关系 <a class="header-anchor" href="#高速能见度和车速之间的关系" aria-label="Permalink to &quot;高速能见度和车速之间的关系&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能见度</th><th>车速</th><th>间距</th></tr></thead><tbody><tr><td>200m</td><td>60km/h</td><td>100m</td></tr><tr><td>100m</td><td>40km/h</td><td>50m</td></tr><tr><td>50m</td><td>20km/h</td><td>离开高速</td></tr></tbody></table><h3 id="车速和车距之间的关系" tabindex="-1">车速和车距之间的关系 <a class="header-anchor" href="#车速和车距之间的关系" aria-label="Permalink to &quot;车速和车距之间的关系&quot;">​</a></h3><ul><li>50km/h以上，安全车距等于车速。</li><li>50km/h以下，车速减10为安全车距。</li></ul><h2 id="儿童乘车要求" tabindex="-1">儿童乘车要求 <a class="header-anchor" href="#儿童乘车要求" aria-label="Permalink to &quot;儿童乘车要求&quot;">​</a></h2><ul><li><strong>12周岁以下不能乘坐副驾驶</strong></li><li><strong>4周岁以下必须使用儿童座椅</strong></li></ul><hr>',51)])])}const m=a(e,[["render",d]]);export{b as __pageData,m as default};
